"use strict";(globalThis.webpackChunksuperpai_docs=globalThis.webpackChunksuperpai_docs||[]).push([[110],{8514(e){e.exports=JSON.parse('{"version":{"pluginId":"superpai","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"superpaiSidebar":[{"type":"link","href":"/docs/whats-new","label":"What\'s New in v3.7.0","docId":"whats-new","unlisted":false},{"type":"link","href":"/docs/marketing","label":"Platform Overview","docId":"marketing","unlisted":false},{"type":"category","label":"User Guide","collapsed":false,"items":[{"type":"link","href":"/docs/user-guide/intro","label":"Getting Started","docId":"user-guide/intro","unlisted":false},{"type":"link","href":"/docs/user-guide/adaptive-depth","label":"Adaptive Depth","docId":"user-guide/adaptive-depth","unlisted":false},{"type":"link","href":"/docs/user-guide/commands","label":"Commands (47)","docId":"user-guide/commands","unlisted":false},{"type":"link","href":"/docs/user-guide/gsd-integration","label":"GSD Integration","docId":"user-guide/gsd-integration","unlisted":false},{"type":"link","href":"/docs/user-guide/skills","label":"Skills (73)","docId":"user-guide/skills","unlisted":false},{"type":"link","href":"/docs/user-guide/agents","label":"Agents (16)","docId":"user-guide/agents","unlisted":false},{"type":"link","href":"/docs/user-guide/development-workflow","label":"Development Workflow","docId":"user-guide/development-workflow","unlisted":false},{"type":"link","href":"/docs/user-guide/multi-session","label":"Multi-Session","docId":"user-guide/multi-session","unlisted":false},{"type":"link","href":"/docs/user-guide/voice","label":"Voice Integration","docId":"user-guide/voice","unlisted":false},{"type":"link","href":"/docs/user-guide/security","label":"Security & Auditing","docId":"user-guide/security","unlisted":false},{"type":"link","href":"/docs/user-guide/cost","label":"Cost Management","docId":"user-guide/cost","unlisted":false},{"type":"link","href":"/docs/user-guide/memory","label":"Memory & Learning","docId":"user-guide/memory","unlisted":false},{"type":"link","href":"/docs/user-guide/troubleshooting","label":"Troubleshooting","docId":"user-guide/troubleshooting","unlisted":false}],"collapsible":true},{"type":"category","label":"Architecture","collapsed":true,"items":[{"type":"link","href":"/docs/architecture/overview","label":"Overview","docId":"architecture/overview","unlisted":false},{"type":"link","href":"/docs/architecture/plugin-core","label":"Plugin Core","docId":"architecture/plugin-core","unlisted":false},{"type":"link","href":"/docs/architecture/hooks","label":"Hooks (13)","docId":"architecture/hooks","unlisted":false},{"type":"link","href":"/docs/architecture/skills","label":"Skills Architecture","docId":"architecture/skills","unlisted":false},{"type":"link","href":"/docs/architecture/agents","label":"Agents Architecture","docId":"architecture/agents","unlisted":false},{"type":"link","href":"/docs/architecture/mcp","label":"MCP Architecture","docId":"architecture/mcp","unlisted":false},{"type":"link","href":"/docs/architecture/server","label":"Server (superpai-server)","docId":"architecture/server","unlisted":false},{"type":"link","href":"/docs/architecture/memory","label":"Memory Architecture","docId":"architecture/memory","unlisted":false},{"type":"link","href":"/docs/architecture/gsd","label":"GSD Architecture","docId":"architecture/gsd","unlisted":false}],"collapsible":true},{"type":"category","label":"IDE Integration","collapsed":true,"items":[{"type":"link","href":"/docs/ide-integration/overview","label":"Overview","docId":"ide-integration/overview","unlisted":false},{"type":"link","href":"/docs/ide-integration/claude-code","label":"Claude Code CLI","docId":"ide-integration/claude-code","unlisted":false},{"type":"link","href":"/docs/ide-integration/claude-desktop","label":"Claude Desktop","docId":"ide-integration/claude-desktop","unlisted":false},{"type":"link","href":"/docs/ide-integration/vscode","label":"VS Code","docId":"ide-integration/vscode","unlisted":false},{"type":"link","href":"/docs/ide-integration/cursor","label":"Cursor","docId":"ide-integration/cursor","unlisted":false},{"type":"link","href":"/docs/ide-integration/windsurf","label":"Windsurf","docId":"ide-integration/windsurf","unlisted":false},{"type":"link","href":"/docs/ide-integration/warp","label":"Warp Terminal","docId":"ide-integration/warp","unlisted":false},{"type":"link","href":"/docs/ide-integration/remote-server","label":"Remote Server","docId":"ide-integration/remote-server","unlisted":false}],"collapsible":true},{"type":"category","label":"Implementation","collapsed":true,"items":[{"type":"link","href":"/docs/implementation/installation","label":"Installation","docId":"implementation/installation","unlisted":false},{"type":"link","href":"/docs/implementation/upgrade","label":"Upgrade Guide","docId":"implementation/upgrade","unlisted":false},{"type":"link","href":"/docs/implementation/configuration","label":"Configuration","docId":"implementation/configuration","unlisted":false},{"type":"link","href":"/docs/implementation/remote-server","label":"Remote Server","docId":"implementation/remote-server","unlisted":false},{"type":"link","href":"/docs/implementation/anna-voice","label":"Anna-Voice Setup","docId":"implementation/anna-voice","unlisted":false},{"type":"link","href":"/docs/implementation/custom-components","label":"Custom Components","docId":"implementation/custom-components","unlisted":false},{"type":"link","href":"/docs/implementation/api-reference","label":"API Reference","docId":"implementation/api-reference","unlisted":false},{"type":"link","href":"/docs/implementation/database","label":"Database","docId":"implementation/database","unlisted":false}],"collapsible":true}]},"docs":{"architecture/agents":{"id":"architecture/agents","title":"Agent Architecture","description":"Agents are persistent AI personas with distinct identities, communication styles, and voice assignments. Unlike skills (which are stateless instruction sets), agents maintain identity and behavioral patterns throughout their engagement.","sidebar":"superpaiSidebar"},"architecture/gsd":{"id":"architecture/gsd","title":"GSD Integration Architecture (v3.7.0)","description":"The GSD (Get Stuff Done) framework was integrated into SuperPAI+ v3.7.0 with zero breaking changes. This document describes the new components, modified components, and the architectural impact of the integration.","sidebar":"superpaiSidebar"},"architecture/hooks":{"id":"architecture/hooks","title":"Hook System Architecture","description":"Hooks are lifecycle event handlers that fire at specific points during a Claude Code session. SuperPAI+ provides 13 hooks that control initialization, safety, tracking, and cleanup.","sidebar":"superpaiSidebar"},"architecture/mcp":{"id":"architecture/mcp","title":"MCP Architecture","description":"SuperPAI+ integrates with IDEs through the Model Context Protocol (MCP). The MCP layer exposes 24 tools, 133 prompts, and 8 resources that allow IDE extensions to access SuperPAI+ capabilities without running the full plugin.","sidebar":"superpaiSidebar"},"architecture/memory":{"id":"architecture/memory","title":"Memory Architecture","description":"The memory system provides persistent context across sessions, projects, and the entire SuperPAI+ platform. It uses a tiered architecture with automatic classification, confidence scoring, and sync capabilities.","sidebar":"superpaiSidebar"},"architecture/overview":{"id":"architecture/overview","title":"Architecture Overview","description":"SuperPAI+ is built as a layered, modular system where each layer has clear responsibilities and well-defined interfaces. This document provides a high-level view of the architecture, component relationships, and design principles.","sidebar":"superpaiSidebar"},"architecture/plugin-core":{"id":"architecture/plugin-core","title":"Plugin Core Architecture","description":"The SuperPAI+ plugin is defined by two core configuration files: plugin.json (the manifest) and hooks.json (the lifecycle registry). Together, they declare all components and control how the plugin integrates with Claude Code.","sidebar":"superpaiSidebar"},"architecture/server":{"id":"architecture/server","title":"Server Architecture","description":"The superpai-server is the persistent backend for SuperPAI+. It provides REST API endpoints for memory, cost tracking, session coordination, and configuration management. Built with Bun and Hono, it stores data in an embedded SQLite database.","sidebar":"superpaiSidebar"},"architecture/skills":{"id":"architecture/skills","title":"Skills Architecture","description":"Skills are the primary mechanism for extending SuperPAI+ with specialized capabilities. Each skill is a self-contained module defined by a SKILL.md file that provides instructions, triggers, and examples for a specific engineering domain.","sidebar":"superpaiSidebar"},"ide-integration/claude-code":{"id":"ide-integration/claude-code","title":"Claude Code CLI Integration","description":"Claude Code CLI is the primary and most fully-featured integration for SuperPAI+. The plugin loads natively into Claude Code, providing access to all 73 skills, 47 commands, 16 agents, and 13 hooks without any MCP configuration.","sidebar":"superpaiSidebar"},"ide-integration/claude-desktop":{"id":"ide-integration/claude-desktop","title":"Claude Desktop Integration","description":"Claude Desktop can access SuperPAI+ capabilities through MCP. This enables using SuperPAI+ tools, prompts, and resources in the Desktop application\'s conversational interface.","sidebar":"superpaiSidebar"},"ide-integration/cursor":{"id":"ide-integration/cursor","title":"Cursor IDE Integration","description":"Cursor supports MCP through its built-in AI features. SuperPAI+ tools can be used alongside Cursor\'s native AI capabilities for enhanced development workflows.","sidebar":"superpaiSidebar"},"ide-integration/overview":{"id":"ide-integration/overview","title":"IDE Integration Overview","description":"SuperPAI+ integrates with multiple IDEs and development environments through the Model Context Protocol (MCP). This enables access to SuperPAI+ tools, prompts, and resources directly within your preferred editor.","sidebar":"superpaiSidebar"},"ide-integration/remote-server":{"id":"ide-integration/remote-server","title":"Remote Server Setup for Teams","description":"Deploy the SuperPAI+ MCP server on a shared machine to enable team-wide access. Team members connect via HTTP transport from any supported IDE.","sidebar":"superpaiSidebar"},"ide-integration/vscode":{"id":"ide-integration/vscode","title":"VS Code Integration","description":"Visual Studio Code supports MCP through the Claude extension. Once configured, SuperPAI+ tools and prompts are available directly in your VS Code editor alongside your code.","sidebar":"superpaiSidebar"},"ide-integration/warp":{"id":"ide-integration/warp","title":"Warp Terminal Integration","description":"Warp terminal supports MCP through its AI mode. SuperPAI+ tools can be accessed within Warp\'s AI-powered terminal experience.","sidebar":"superpaiSidebar"},"ide-integration/windsurf":{"id":"ide-integration/windsurf","title":"Windsurf Integration","description":"Windsurf (by Codeium) supports MCP through its Cascade AI feature. SuperPAI+ tools can be used within Windsurf\'s AI-powered development workflow.","sidebar":"superpaiSidebar"},"implementation/anna-voice":{"id":"implementation/anna-voice","title":"Anna-Voice Setup","description":"This guide covers how to install and configure Anna-Voice for use with SuperPAI+. Anna-Voice provides text-to-speech (TTS) and speech-to-text (STT) capabilities with 21 distinct voice personas.","sidebar":"superpaiSidebar"},"implementation/api-reference":{"id":"implementation/api-reference","title":"REST API Reference","description":"The superpai-server exposes a REST API for persistent storage, session coordination, cost tracking, and system management. All endpoints accept and return JSON.","sidebar":"superpaiSidebar"},"implementation/configuration":{"id":"implementation/configuration","title":"Configuration Reference","description":"SuperPAI+ is configurable through settings files, environment variables, and runtime commands. This reference documents all available configuration options.","sidebar":"superpaiSidebar"},"implementation/custom-components":{"id":"implementation/custom-components","title":"Creating Custom Components","description":"SuperPAI+ is designed to be extended with custom skills, commands, agents, steering rules, and identity configurations. This guide provides templates and instructions for creating each component type.","sidebar":"superpaiSidebar"},"implementation/database":{"id":"implementation/database","title":"Database Reference","description":"SuperPAI+ uses an embedded SQLite database for persistent storage. The database is located at superpai-server/data/superpai.db and contains 11 tables that store sessions, memory, cost data, coordination messages, and system configuration.","sidebar":"superpaiSidebar"},"implementation/installation":{"id":"implementation/installation","title":"Installing SuperPAI+","description":"This guide walks through the complete installation process for SuperPAI+ on all supported platforms.","sidebar":"superpaiSidebar"},"implementation/remote-server":{"id":"implementation/remote-server","title":"Remote Server Deployment","description":"Deploy the superpai-server to a shared machine for team-wide access. This guide covers Ubuntu deployment, systemd service configuration, Nginx reverse proxy with HTTPS, and Kubernetes manifests.","sidebar":"superpaiSidebar"},"implementation/upgrade":{"id":"implementation/upgrade","title":"Upgrading SuperPAI+","description":"Upgrading SuperPAI+ is a straightforward three-step process. This guide covers the upgrade procedure, version-specific changes, and component behavior during upgrades.","sidebar":"superpaiSidebar"},"marketing":{"id":"marketing","title":"SuperPAI+ Platform Overview","description":"SuperPAI+ is the most comprehensive AI-assisted engineering platform available today. Built as a plugin for Claude Code, it transforms a general-purpose AI assistant into a full-stack engineering partner with deep domain knowledge, persistent memory, voice interaction, multi-session coordination, and over 70 specialized skills.","sidebar":"superpaiSidebar"},"user-guide/adaptive-depth":{"id":"user-guide/adaptive-depth","title":"Adaptive Depth System","description":"The Adaptive Depth System is the brain of SuperPAI+. It automatically selects the right level of effort, planning, and tooling for every task --- from instant answers to multi-day architectural refactors.","sidebar":"superpaiSidebar"},"user-guide/agents":{"id":"user-guide/agents","title":"AI Agents (16)","description":"SuperPAI+ includes 16 specialized AI agents, each with a distinct persona, expertise area, voice, and communication style. Agents go beyond skills by maintaining a persistent identity and behavioral pattern throughout their engagement.","sidebar":"superpaiSidebar"},"user-guide/commands":{"id":"user-guide/commands","title":"Slash Commands","description":"SuperPAI+ provides 47 slash commands organized into functional categories. Each command is available by typing / followed by the command name in any Claude Code session with SuperPAI+ loaded.","sidebar":"superpaiSidebar"},"user-guide/cost":{"id":"user-guide/cost","title":"Cost Management","description":"SuperPAI+ provides real-time cost tracking for all AI model usage across sessions. The cost system monitors token consumption per model, calculates running totals, and provides optimization recommendations.","sidebar":"superpaiSidebar"},"user-guide/development-workflow":{"id":"user-guide/development-workflow","title":"Development Workflow","description":"SuperPAI+ enforces a structured development workflow that ensures quality, consistency, and traceability. This guide covers the standard WORKFLOW mode flow, TDD enforcement, git worktrees, and code review processes.","sidebar":"superpaiSidebar"},"user-guide/gsd-integration":{"id":"user-guide/gsd-integration","title":"GSD Integration (v3.7.0)","description":"The GSD (Get Stuff Done) framework is the marquee feature of SuperPAI+ v3.7.0. It introduces spec-driven development, wave-based planning, model aliases, and atomic commits to create a streamlined, high-throughput development workflow.","sidebar":"superpaiSidebar"},"user-guide/intro":{"id":"user-guide/intro","title":"Getting Started with SuperPAI+","description":"Welcome to SuperPAI+, the personal AI infrastructure that transforms Claude Code into a full engineering platform. This guide will take you from installation to your first productive session in under 10 minutes.","sidebar":"superpaiSidebar"},"user-guide/memory":{"id":"user-guide/memory","title":"Memory & Learning System","description":"SuperPAI+ includes a persistent memory system that captures patterns, decisions, and context across sessions. The memory system enables the AI to learn from past interactions and continuously improve its effectiveness.","sidebar":"superpaiSidebar"},"user-guide/multi-session":{"id":"user-guide/multi-session","title":"Multi-Session Coordination","description":"SuperPAI+ supports running multiple Claude Code sessions simultaneously with automatic coordination to prevent conflicts, share progress, and distribute work across parallel sessions.","sidebar":"superpaiSidebar"},"user-guide/security":{"id":"user-guide/security","title":"Security & Auditing","description":"SuperPAI+ includes comprehensive security tooling with over 150 automated checks, penetration testing workflows, reconnaissance capabilities, and a constitutional safety gate system.","sidebar":"superpaiSidebar"},"user-guide/skills":{"id":"user-guide/skills","title":"Skills System (73 Skills)","description":"Skills are the foundational building blocks of SuperPAI+. Each skill is a self-contained capability defined by a SKILL.md file that teaches the AI how to perform a specific engineering task with expertise and consistency.","sidebar":"superpaiSidebar"},"user-guide/troubleshooting":{"id":"user-guide/troubleshooting","title":"Troubleshooting","description":"This guide covers common issues with SuperPAI+ and their solutions. If your issue is not listed here, check the GitLab Issues page or reach out on the engineering Slack channel.","sidebar":"superpaiSidebar"},"user-guide/voice":{"id":"user-guide/voice","title":"Voice Integration (Anna-Voice)","description":"SuperPAI+ integrates with Anna-Voice to provide spoken output, voice input, and agent-specific voice personas. This creates a natural, multimodal development experience where agents speak their progress, ask questions aloud, and respond to voice commands.","sidebar":"superpaiSidebar"},"whats-new":{"id":"whats-new","title":"What\'s New in SuperPAI+ v3.7.0","description":"Release Date GSD (Get Stuff Done)","sidebar":"superpaiSidebar"}}}}')}}]);